={{ (() => {
  const nativeLang = $('Prep Onboarding Start').item.json.nativeLang || 'en';
  const targetLang = $('Prep Onboarding Start').item.json.targetLang || 'en';
  const LANG = { ru:'Russian',en:'English',es:'Spanish',zh:'Chinese',ar:'Arabic',
    pt:'Portuguese',fr:'French',de:'German',hi:'Hindi',ja:'Japanese',
    ko:'Korean',it:'Italian',tr:'Turkish',pl:'Polish',uk:'Ukrainian',
    nl:'Dutch',sv:'Swedish',vi:'Vietnamese',th:'Thai',id:'Indonesian' };
  const nativeName = LANG[nativeLang] || nativeLang;
  const targetName = LANG[targetLang] || targetLang;
  const system = `Write EVERYTHING in ${nativeName} ONLY.

You are starting a ${targetName} level assessment.

Write a warm 2-3 sentence welcome in ${nativeName}. Clearly tell the student that their answers should be in ${targetName} (this is important — emphasize it). Then ask Question 1/4: their name and where they are from — write the question itself in ${targetName} so the student sees the language they must use.`;
  return JSON.stringify({ model: 'claude-haiku-4-5', max_tokens: 400,
    system, messages: [{ role: 'user', content: '__start__' }] });
})() }}

parameters.jsCode:
const cbData = $('Router').item.json.cbData || '';
const userId = $('Router').item.json.userId;
const answerIdx = parseInt(cbData.replace('quiz_ans_', ''));
const quizRaw = $('Load Quiz For Answer').item.json.value || '{}';
const quiz = JSON.parse(quizRaw);

// Ignore duplicate/stale button presses (question already answered)
if (quiz.answers.length >= quiz.questions.length || quiz.answers.length !== quiz.current) {
  return [];
}

quiz.answers.push(answerIdx);
quiz.current += 1;

const isFinished = quiz.current >= quiz.questions.length;
const updatedJson = JSON.stringify(quiz);
const correctCount = quiz.answers.filter((a, i) => a === quiz.questions[i].correct).length;

return [{ json: {
  userId,
  quizJson: updatedJson,
  quiz,
  isFinished,
  correctCount,
  nativeLang: quiz.nativeLang || 'en',
  level: quiz.level || 'A1'
} }];

