={{ (() => {
  const quiz = $('Process Quiz Answer').item.json.quiz;
  const nativeLang = quiz.nativeLang || 'en';
  const correctCount = $('Process Quiz Answer').item.json.correctCount;
  const total = quiz.questions.length;
  const LANG = { ru:'Russian',en:'English',es:'Spanish',zh:'Chinese',ar:'Arabic',
    pt:'Portuguese',fr:'French',de:'German',hi:'Hindi',ja:'Japanese',
    ko:'Korean',it:'Italian',tr:'Turkish',pl:'Polish',uk:'Ukrainian' };
  const nativeName = LANG[nativeLang] || nativeLang;

  const wrongOnes = [];
  quiz.questions.forEach(function(q, i) {
    if (quiz.answers[i] !== q.correct) {
      const studentAns = q.options[quiz.answers[i]] || '?';
      wrongOnes.push(
        'Q' + (i+1) + ': ' + q.q + '\n' +
        'Student answered: ' + studentAns + '\n' +
        'Correct: ' + q.options[q.correct] + '\n' +
        'Explanation hint: ' + q.explanation
      );
    }
  });

  const wrongSummary = wrongOnes.length > 0 ? wrongOnes.join('\n\n') : 'All answers were correct!';
  const xp = correctCount * 5 + (correctCount === total ? 20 : 0);

  const prompt = 'The student just completed a language quiz. Score: ' + correctCount + '/' + total + '.\n' +
    'Write the result summary in ' + nativeName + ' ONLY.\n\n' +
    (wrongOnes.length > 0 ? 'Wrong answers to explain:\n\n' + wrongSummary : 'All answers correct!') +
    '\n\nFormat your response:\n' +
    '1. Start with an emoji + score line (e.g. 🏆 18/20) and a warm reaction in ' + nativeName + '\n' +
    '2. XP earned: ' + xp + ' XP\n' +
    '3. If there are wrong answers: for each one, explain clearly in ' + nativeName + ' WHY the correct answer is right. Use this format:\n' +
    '   ❌ Q[N]: [question]\n' +
    '   ✅ Correct: [answer]\n' +
    '   💡 [clear explanation in ' + nativeName + ']\n' +
    '4. End with a short encouraging message in ' + nativeName + '.\n\n' +
    'Keep it clear and educational. Max 1500 characters.';

  return JSON.stringify({ model: 'claude-haiku-4-5', max_tokens: 1500,
    messages: [{ role: 'user', content: prompt }] });
})() }}

