UPDATE users SET total_xp = total_xp + {{ 
  $('Process Quiz Answer').item.json.correctCount * 5 + 
  ($('Process Quiz Answer').item.json.correctCount === $('Process Quiz Answer').item.json.quiz.questions.length ? 20 : 0)
}} WHERE id = {{ $('Router').item.json.userId }};

