={{ (() => {
  const userId = $('Router').item.json.userId;
  const nativeLang = $('Router').item.json.nativeLang || 'en';
  const quizRaw = $('Get Quiz State').item.json.value || '{}';
  let quiz = {};
  try { quiz = JSON.parse(quizRaw); } catch(e) {}
  const current = quiz.current || 0;
  const total = (quiz.questions || []).length || 20;
  const MSGS = {
    ru: `🎯 У тебя есть незавершённый квиз!

Пройдено: ${current}/${total} вопросов

Продолжить с вопроса ${current+1} или начать заново?`,
    en: `🎯 You have an unfinished quiz!

Progress: ${current}/${total} questions

Continue from question ${current+1} or start over?`,
    es: `🎯 ¡Tienes un cuestionario sin terminar!

Progreso: ${current}/${total} preguntas

¿Continuar desde la pregunta ${current+1} o empezar de nuevo?`,
    uk: `🎯 У тебе є незавершений квіз!

Пройдено: ${current}/${total} питань

Продовжити з питання ${current+1} або почати заново?`,
    de: `🎯 Du hast ein unvollendetes Quiz!

Fortschritt: ${current}/${total} Fragen

Weiter mit Frage ${current+1} oder neu starten?`,
    fr: `🎯 Tu as un quiz inachevé !

Progression : ${current}/${total} questions

Continuer à partir de la question ${current+1} ou recommencer ?`,
    zh: `🎯 你有一个未完成的测验！

进度：${current}/${total} 题

从第${current+1}题继续还是重新开始？`,
  };
  const BTN_CONTINUE = {ru:'▶️ Продолжить',en:'▶️ Continue',es:'▶️ Continuar',uk:'▶️ Продовжити',de:'▶️ Weiter',fr:'▶️ Continuer',zh:'▶️ 继续'};
  const BTN_NEW = {ru:'🔄 Начать заново',en:'🔄 Start over',es:'🔄 Empezar de nuevo',uk:'🔄 Почати заново',de:'🔄 Neu starten',fr:'🔄 Recommencer',zh:'🔄 重新开始'};
  const text = MSGS[nativeLang] || MSGS['en'];
  const btnContinue = BTN_CONTINUE[nativeLang] || BTN_CONTINUE['en'];
  const btnNew = BTN_NEW[nativeLang] || BTN_NEW['en'];
  return JSON.stringify({ chat_id: userId, text,
    reply_markup: { inline_keyboard: [[
      { text: btnContinue, callback_data: 'quiz_continue' },
      { text: btnNew, callback_data: 'quiz_new' }
    ]]}
  });
})() }}

