parameters.jsCode:
const raw = $('Generate Quiz').item.json.content[0].text;
// Extract JSON array from Claude response (strip any surrounding text)
const match = raw.match(/\[\s*\{[\s\S]*\}\s*\]/);
if (!match) throw new Error('Could not parse quiz JSON from Claude response');
const questions = JSON.parse(match[0]);
const userId = $('Router').item.json.userId;
const level = $('Router').item.json.level || 'A1';
const nativeLang = $('Router').item.json.nativeLang || 'en';
const targetLang = $('Router').item.json.targetLang || 'en';

const quizState = {
  questions: questions.slice(0, 20),
  current: 0,
  answers: [],
  level, nativeLang, targetLang,
  startedAt: Date.now()
};
return [{ json: {
  userId,
  quizJson: JSON.stringify(quizState),
  quiz: quizState,
  nativeLang, level
} }];

parameters.body:
={{ (() => {
  const userId = $('Router').item.json.userId;
  // Load quiz from upstream — either Save Quiz (new) or Load Quiz For Question (continue/answer)
  let quizRaw = '';
  try { quizRaw = $('Save Quiz').item.json.quizJson; } catch(e) {}
  if (!quizRaw) { try { quizRaw = $('Load Quiz For Question').item.json.value; } catch(e) {} }
  const quiz = JSON.parse(quizRaw);
  const q = quiz.questions[quiz.current];
  const num = quiz.current + 1;
  const total = quiz.questions.length;
  const nativeLang = quiz.nativeLang || 'en';
  const PROGRESS_LABEL = {ru:'Вопрос',en:'Question',es:'Pregunta',uk:'Питання',de:'Frage',fr:'Question',zh:'题目',ar:'سؤال'};
  const label = PROGRESS_LABEL[nativeLang] || PROGRESS_LABEL['en'];
  const TOPIC_LABEL = {
    grammar: {ru:'📝 Грамматика',en:'📝 Grammar',es:'📝 Gramática',uk:'📝 Граматика',de:'📝 Grammatik',fr:'📝 Grammaire',zh:'📝 语法'},
    vocabulary: {ru:'📚 Словарный запас',en:'📚 Vocabulary',es:'📚 Vocabulario',uk:'📚 Словниковий запас',de:'📚 Vokabular',fr:'📚 Vocabulaire',zh:'📚 词汇'}
  };
  const topicLabel = (TOPIC_LABEL[q.topic] || TOPIC_LABEL['vocabulary'])[nativeLang] || q.topic;
  const text = `${topicLabel} · ${label} ${num}/${total}

${q.q}`;
  const letters = ['A', 'B', 'C', 'D'];
  const rows = q.options.map((opt, i) => ([{ text: `${letters[i]}) ${opt}`, callback_data: `quiz_ans_${i}` }]));
  return JSON.stringify({ chat_id: userId, text, reply_markup: { inline_keyboard: rows } });
})() }}
